const isCoprime = (a, b) => {
  const gcd = (x, y) => (y === 0 ? x : gcd(y, x % y));
  return gcd(a, b) === 1;
};

const mmi = (a, m) => {
  for (let x = 1; x < m; x++) {
    if ((a * x) % m === 1) return x;
  }
  return -1;
};

export const encode = (phrase, key) => {
  const { a, b } = key;
  const m = 26;

  if (!isCoprime(a, m)) {
    throw new Error('a and m must be coprime.');
  }

  const filtered = phrase.toLowerCase().replace(/[^a-z0-9]/g, '');

  let encoded = '';
  for (const char of filtered) {
    if (char >= '0' && char <= '9') {
      encoded += char;
    } else {
      const i = char.charCodeAt(0) - 97;
      const encrypted = (a * i + b) % m;
      encoded += String.fromCharCode(encrypted + 97);
    }
  }

  const groups = [];
  for (let i = 0; i < encoded.length; i += 5) {
    groups.push(encoded.substring(i, i + 5));
  }
  return groups.join(' ');
};

export const decode = (phrase, key) => {
  const { a, b } = key;
  const m = 26;

  if (!isCoprime(a, m)) {
    throw new Error('a and m must be coprime.');
  }

  const aInverse = mmi(a, m);

  const filtered = phrase.replace(/\s/g, '');

  let decoded = '';
  for (const char of filtered) {
    if (char >= '0' && char <= '9') {
      decoded += char;
    } else {
      const y = char.charCodeAt(0) - 97;
      const decrypted = ((aInverse * (y - b)) % m + m) % m;
      decoded += String.fromCharCode(decrypted + 97);
    }
  }

  return decoded;
};

