export const solve = (puzzle) => {
  const [left, result] = puzzle.split('=').map(s => s.trim());
  const terms = left.split('+').map(s => s.trim());

  const maxLen = Math.max(...terms.map(t => t.length), result.length);

  // Build column data: for each column (right to left), track addend letter counts and result letter
  const columns = [];
  for (let i = 0; i < maxLen; i++) {
    const addendCounts = new Map();
    for (const term of terms) {
      const idx = term.length - 1 - i;
      if (idx >= 0) {
        const letter = term[idx];
        addendCounts.set(letter, (addendCounts.get(letter) || 0) + 1);
      }
    }
    const resIdx = result.length - 1 - i;
    const resultLetter = resIdx >= 0 ? result[resIdx] : null;
    columns.push({ addendCounts, resultLetter });
  }

  // Leading letters of multi-digit words cannot be zero
  const leadingLetters = new Set();
  [...terms, result].forEach(word => {
    if (word.length > 1) leadingLetters.add(word[0]);
  });

  const mapping = {};
  const used = new Set();

  const solveColumn = (colIdx, carryIn) => {
    if (colIdx >= columns.length) return carryIn === 0;

    const { addendCounts, resultLetter } = columns[colIdx];

    let partialSum = carryIn;
    const unassigned = []; // [letter, count][]

    for (const [letter, count] of addendCounts) {
      if (letter in mapping) {
        partialSum += mapping[letter] * count;
      } else {
        unassigned.push([letter, count]);
      }
    }

    const resultAssigned = resultLetter !== null && resultLetter in mapping;

    const tryAssign = (idx, sum) => {
      if (idx === unassigned.length) {
        const digit = sum % 10;
        const carry = Math.floor(sum / 10);

        if (resultLetter === null) {
          return sum === 0 && solveColumn(colIdx + 1, 0);
        }

        if (resultAssigned) {
          return mapping[resultLetter] === digit && solveColumn(colIdx + 1, carry);
        }

        if (digit === 0 && leadingLetters.has(resultLetter)) return false;
        if (used.has(digit)) return false;

        mapping[resultLetter] = digit;
        used.add(digit);
        const ok = solveColumn(colIdx + 1, carry);
        delete mapping[resultLetter];
        used.delete(digit);
        return ok;
      }

      const [letter, count] = unassigned[idx];
      for (let d = 0; d <= 9; d++) {
        if (used.has(d)) continue;
        if (d === 0 && leadingLetters.has(letter)) continue;

        mapping[letter] = d;
        used.add(d);
        if (tryAssign(idx + 1, sum + d * count)) return true;
        delete mapping[letter];
        used.delete(d);
      }
      return false;
    };

    return tryAssign(0, partialSum);
  };

  return solveColumn(0, 0) ? { ...mapping } : null;
};

