export const recite = (initialBottlesCount, takeDownCount) => {
  const generateVerse = (count) => {
    if (count === 0) {
      return `No more bottles of beer on the wall, no more bottles of beer.\nGo to the store and buy some more, 99 bottles of beer on the wall.`;
    }

    const currentBottleText = count === 1 ? '1 bottle' : `${count} bottles`;
    const nextCount = count - 1;

    let nextBottleText;
    if (nextCount === 0) {
      nextBottleText = 'no more bottles';
    } else if (nextCount === 1) {
      nextBottleText = '1 bottle';
    } else {
      nextBottleText = `${nextCount} bottles`;
    }

    const action = count === 1 ? 'Take it down' : 'Take one down';

    return `${currentBottleText} of beer on the wall, ${currentBottleText} of beer.\n${action} and pass it around, ${nextBottleText} of beer on the wall.`;
  };

  const verses = [];
  for (let i = 0; i < takeDownCount; i++) {
    verses.push(generateVerse(initialBottlesCount - i));
  }

  return verses.join('\n\n');
};

