export const cost = (books) => {
  const counts = [0, 0, 0, 0, 0];
  for (const book of books) {
    counts[book - 1]++;
  }
  const total = counts.reduce((a, b) => a + b, 0);
  if (total === 0) return 0;

  const prices = [0, 800, 1520, 2160, 2560, 3000];
  let minCost = Infinity;

  for (let x5 = 0; x5 <= Math.floor(total / 5); x5++) {
    const rem5 = total - 5 * x5;
    for (let x4 = 0; x4 <= Math.floor(rem5 / 4); x4++) {
      const rem4 = rem5 - 4 * x4;
      for (let x3 = 0; x3 <= Math.floor(rem4 / 3); x3++) {
        const rem3 = rem4 - 3 * x3;
        for (let x2 = 0; x2 <= Math.floor(rem3 / 2); x2++) {
          const x1 = rem3 - 2 * x2;
          let feasible = true;
          for (let mask = 1; mask < 32; mask++) {
            let s = 0;
            let copies = 0;
            for (let i = 0; i < 5; i++) {
              if (mask & (1 << i)) {
                s++;
                copies += counts[i];
              }
            }
            const capacity = 
              x5 * Math.min(5, s) +
              x4 * Math.min(4, s) +
              x3 * Math.min(3, s) +
              x2 * Math.min(2, s) +
              x1 * Math.min(1, s);
            if (copies > capacity) {
              feasible = false;
              break;
            }
          }
          if (feasible) {
            const cost = 
              x5 * prices[5] +
              x4 * prices[4] +
              x3 * prices[3] +
              x2 * prices[2] +
              x1 * prices[1];
            if (cost < minCost) minCost = cost;
          }
        }
      }
    }
  }
  return minCost;
};

