      throw new Error('Cannot roll after game is over');
    }

    if (!this._isValidRoll(pins)) {
      throw new Error('Invalid roll');
    }

    this.rolls.push(pins);
  }

  score() {
    if (!this._isGameOver()) {
      throw new Error('Score cannot be taken until the end of the game');
    }

    let total = 0;
    let rollIndex = 0;

    for (let frame = 0; frame < 10; frame++) {
      if (this.rolls[rollIndex] === 10) {
        // Strike
        total += 10 + this.rolls[rollIndex + 1] + this.rolls[rollIndex + 2];
        rollIndex += 1;
      } else if (this.rolls[rollIndex] + this.rolls[rollIndex + 1] === 10) {
        // Spare
        total += 10 + this.rolls[rollIndex + 2];
        rollIndex += 2;
      } else {
        // Open frame
        total += this.rolls[rollIndex] + this.rolls[rollIndex + 1];
        rollIndex += 2;
      }
    }

    return total;
  }

  _isGameOver() {
    let rollIndex = 0;

    for (let frame = 0; frame < 9; frame++) {
      if (this.rolls[rollIndex] === 10) {
        rollIndex += 1;
      } else {
        rollIndex += 2;
      }
    }

    const tenthFrameRolls = this.rolls.length - rollIndex;

    if (tenthFrameRolls < 2) return false;
    if (tenthFrameRolls >= 3) return true;

    const first = this.rolls[rollIndex];
    const second = this.rolls[rollIndex + 1];

    if (first === 10 || first + second === 10) {
      return false;
    }

    return true;
  }

  _isValidRoll(pins) {
    let rollIndex = 0;

    for (let frame = 0; frame < 9; frame++) {
      if (rollIndex >= this.rolls.length) return true;
      if (this.rolls[rollIndex] === 10) {
        rollIndex += 1;
      } else if (rollIndex + 1 < this.rolls.length) {
        rollIndex += 2;
      } else {
        return this.rolls[rollIndex] + pins <= 10;
      }
    }

    // 10th frame
    const tenthStart = rollIndex;
    const tenthRolls = this.rolls.length - tenthStart;

    if (tenthRolls === 0) return true;

    if (tenthRolls === 1) {
      if (this.rolls[tenthStart] === 10) return true;
      return this.rolls[tenthStart] + pins <= 10;
    }

    if (tenthRolls === 2) {
      const first = this.rolls[tenthStart];
      const second = this.rolls[tenthStart + 1];
      if (first === 10) {
        if (second === 10) return true;
        return second + pins <= 10;
      }
      return true;
    }

    return true;
  }
}

