      DIGITS[d][0] === chunk[0] &&
      DIGITS[d][1] === chunk[1] &&
      DIGITS[d][2] === chunk[2] &&
      DIGITS[d][3] === chunk[3]
    ) {
      return String(d);
    }
  }
