  let result = "";
  for (let i = 0; i < numDigits; i++) {
    const col = i * 3;
    const chunk = [
      padded[0].substring(col, col + 3),
      padded[1].substring(col, col + 3),
      padded[2].substring(col, col + 3),
      padded[3].substring(col, col + 3),
    ];
    result += parseDigit(chunk);
  }
  return result;
}

