  const translateWord = (word) => {
    if (!word) return '';

    const vowels = 'aeiou';

    // Rule 1: vowel start, "xr", or "yt"
    if (vowels.includes(word[0]) || word.startsWith('xr') || word.startsWith('yt')) {
      return word + 'ay';
    }

    let i = 0;
    let consonants = '';

    while (i < word.length) {
      const ch = word[i];

      // Stop at a vowel
      if (vowels.includes(ch)) {
        break;
      }

      // Rule 3: "qu" (including any preceding consonants)
      if (ch === 'q' && i + 1 < word.length && word[i + 1] === 'u') {
        consonants += 'qu';
        i += 2;
        break;
      }

      // Rule 4: "y" after at least one consonant
      if (ch === 'y' && i > 0) {
        break;
      }

      // Default: consonant (including initial 'y')
      consonants += ch;
      i++;
    }

    // All rules result in: substring(i) + consonants + 'ay'
    return word.substring(i) + consonants + 'ay';
  };

  return phrase.split(' ').map(translateWord).join(' ');
};

