export function count(diagram) {
  if (!diagram || diagram.length === 0) return 0;

  const rows = diagram.length;
  const cols = diagram[0].length;

  // Find all positions of '+'
  const plusPositions = [];
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (diagram[r][c] === '+') {
        plusPositions.push([r, c]);
      }
    }
  }

  let count = 0;

  // For each pair of '+' as potential top-left and bottom-right corners
  for (let i = 0; i < plusPositions.length; i++) {
    for (let j = i + 1; j < plusPositions.length; j++) {
      const [r1, c1] = plusPositions[i];
      const [r2, c2] = plusPositions[j];

      // top-left must be above and to the left of bottom-right
      if (r1 >= r2 || c1 >= c2) continue;

      // Check if top-right and bottom-left corners exist as '+'
      if (diagram[r1][c2] !== '+') continue;
      if (diagram[r2][c1] !== '+') continue;

      // Check top edge: all chars between (r1,c1) and (r1,c2) must be '-' or '+'
      let valid = true;
      for (let c = c1 + 1; c < c2; c++) {
        const ch = diagram[r1][c];
        if (ch !== '-' && ch !== '+') {
          valid = false;
          break;
        }
      }
      if (!valid) continue;

      // Check bottom edge
      for (let c = c1 + 1; c < c2; c++) {
        const ch = diagram[r2][c];
        if (ch !== '-' && ch !== '+') {
          valid = false;
          break;
        }
      }
      if (!valid) continue;

      // Check left edge
      for (let r = r1 + 1; r < r2; r++) {
        const ch = diagram[r][c1];
        if (ch !== '|' && ch !== '+') {
          valid = false;
          break;
        }
      }
      if (!valid) continue;

      // Check right edge
      for (let r = r1 + 1; r < r2; r++) {
        const ch = diagram[r][c2];
        if (ch !== '|' && ch !== '+') {
          valid = false;
          break;
        }
      }
      if (!valid) continue;

      count++;
    }
  }

  return count;
}

