    if (path === '/users') {
      let users = this.db.users;
      if (queryString) {
        const params = new URLSearchParams(queryString);
        const names = params.get('users').split(',');
        users = users.filter(u => names.includes(u.name));
      }
      return {
        users: users
          .map(u => this.buildUserResponse(u))
          .sort((a, b) => a.name.localeCompare(b.name))
      };
    }
  }

  post(url, payload) {
    if (url === '/add') {
      const newUser = {
        name: payload.user,
        owes: {},
        owed_by: {},
        balance: 0
      };
      this.db.users.push(newUser);
      return this.buildUserResponse(newUser);
    }

    if (url === '/iou') {
      const { lender, borrower, amount } = payload;
      const lenderUser = this.db.users.find(u => u.name === lender);
      const borrowerUser = this.db.users.find(u => u.name === borrower);

      // Net out any existing debt between these two users
      const lenderOwesBorrower = lenderUser.owes[borrower] || 0;
      const borrowerOwesLender = borrowerUser.owes[lender] || 0;

      if (lenderOwesBorrower > 0) {
        // Lender currently owes borrower; reduce or reverse with this IOU
        const net = lenderOwesBorrower - amount;
        if (net > 0) {
          lenderUser.owes[borrower] = net;
          borrowerUser.owed_by[lender] = net;
        } else {
          delete lenderUser.owes[borrower];
          delete borrowerUser.owed_by[lender];
          if (net < 0) {
            const remaining = -net;
            borrowerUser.owes[lender] = remaining;
            lenderUser.owed_by[borrower] = remaining;
          }
        }
      } else {
        // Add to existing debt or create new
        borrowerUser.owes[lender] = borrowerOwesLender + amount;
        lenderUser.owed_by[borrower] = (lenderUser.owed_by[borrower] || 0) + amount;
      }

      // Recalculate balances
      lenderUser.balance = this.calcBalance(lenderUser);
      borrowerUser.balance = this.calcBalance(borrowerUser);

      return {
        users: [lenderUser, borrowerUser]
          .map(u => this.buildUserResponse(u))
          .sort((a, b) => a.name.localeCompare(b.name))
      };
    }
  }

