export const say = (n) => {
  if (n < 0 || n > 999999999999) {
    throw new Error('Number must be between 0 and 999,999,999,999.');
  }

  if (n === 0) return 'zero';

  const ones = [
    '', 'one', 'two', 'three', 'four', 'five', 'six', 'seven', 'eight', 'nine',
    'ten', 'eleven', 'twelve', 'thirteen', 'fourteen', 'fifteen', 'sixteen',
    'seventeen', 'eighteen', 'nineteen'
  ];

  const tens = [
    '', '', 'twenty', 'thirty', 'forty', 'fifty',
    'sixty', 'seventy', 'eighty', 'ninety'
  ];

  function sayBelow100(num) {
    if (num < 20) return ones[num];
    const t = Math.floor(num / 10);
    const o = num % 10;
    return o === 0 ? tens[t] : `${tens[t]}-${ones[o]}`;
  }

  function sayBelow1000(num) {
    if (num < 100) return sayBelow100(num);
    const h = Math.floor(num / 100);
    const rest = num % 100;
    if (rest === 0) return `${ones[h]} hundred`;
    return `${ones[h]} hundred ${sayBelow100(rest)}`;
  }

  const scales = ['', 'thousand', 'million', 'billion'];
  const parts = [];
  let chunkIndex = 0;

  while (n > 0) {
    const chunk = n % 1000;
    if (chunk !== 0) {
      const chunkWords = sayBelow1000(chunk);
      if (scales[chunkIndex]) {
        parts.unshift(`${chunkWords} ${scales[chunkIndex]}`);
      } else {
        parts.unshift(chunkWords);
      }
    }
    n = Math.floor(n / 1000);
    chunkIndex++;
  }

  return parts.join(' ');
};

