export class TwoBucket {
  constructor(bucketOne, bucketTwo, goal, startBucket) {
    this.bucketOneSize = bucketOne;
    this.bucketTwoSize = bucketTwo;
    this.goal = goal;
    this.startBucket = startBucket;
  }

  solve() {
    const cap1 = this.bucketOneSize;
    const cap2 = this.bucketTwoSize;
    const goal = this.goal;
    const startBucket = this.startBucket;

    // Helper function for greatest common divisor
    const gcd = (a, b) => (b === 0 ? a : gcd(b, a % b));

    // Early checks for impossibility
    if (goal > Math.max(cap1, cap2)) {
      throw new Error('Goal is larger than both buckets');
    }
    if (goal % gcd(cap1, cap2) !== 0) {
      throw new Error('Goal is not reachable');
    }

    // BFS
    const visited = new Set();
    const queue = [];

    // Starting state: fill the start bucket
    let initial;
    if (startBucket === 'one') {
      initial = [cap1, 0, 1]; // [bucket1, bucket2, moves]
    } else {
      initial = [0, cap2, 1];
    }

    // Check if initial state already meets the goal
    if (initial[0] === goal) {
      return { moves: 1, goalBucket: 'one', otherBucket: initial[1] };
    }
    if (initial[1] === goal) {
      return { moves: 1, goalBucket: 'two', otherBucket: initial[0] };
    }

    const key = (a, b) => `${a},${b}`;
    visited.add(key(initial[0], initial[1]));
    queue.push(initial);

    const isForbidden = (a, b) => {
      if (startBucket === 'one') {
        return a === 0 && b === cap2;
      } else {
        return b === 0 && a === cap1;
      }
    };

    while (queue.length > 0) {
      const [a, b, moves] = queue.shift();

      // Generate all possible next states
      const nextStates = [];

      // Fill bucket 1
      nextStates.push([cap1, b]);
      // Fill bucket 2
      nextStates.push([a, cap2]);
      // Empty bucket 1
      nextStates.push([0, b]);
      // Empty bucket 2
      nextStates.push([a, 0]);
      // Pour bucket 1 into bucket 2
      const pour1to2 = Math.min(a, cap2 - b);
      nextStates.push([a - pour1to2, b + pour1to2]);
      // Pour bucket 2 into bucket 1
      const pour2to1 = Math.min(b, cap1 - a);
      nextStates.push([a + pour2to1, b - pour2to1]);

      for (const [na, nb] of nextStates) {
        // Check if this state is forbidden
        if (isForbidden(na, nb)) continue;

        // Check if we reached the goal
        if (na === goal) {
          return { moves: moves + 1, goalBucket: 'one', otherBucket: nb };
        }
        if (nb === goal) {
          return { moves: moves + 1, goalBucket: 'two', otherBucket: na };
        }

        const k = key(na, nb);
        if (!visited.has(k)) {
          visited.add(k);
          queue.push([na, nb, moves + 1]);
        }
      }
    }

    throw new Error('No solution found');
  }
