export const encode = (numbers) => {
  const result = [];
  for (const num of numbers) {
    if (num === 0) {
      result.push(0x00);
    } else {
      let bytes = [];
      let n = num;
      while (n > 0) {
        bytes.push(n & 0x7F);
        n >>>= 7;
      }
      bytes.reverse();
      for (let i = 0; i < bytes.length - 1; i++) {
        bytes[i] |= 0x80;
      }
      result.push(...bytes);
    }
  }
  return result;
};

export const decode = (bytes) => {
  const result = [];
  let current = 0;
  let count = 0;
  for (const byte of bytes) {
    count++;
    current = current * 128 + (byte & 0x7F);
    if ((byte & 0x80) === 0) {
      result.push(current);
      current = 0;
      count = 0;
    }
  }
  if (count > 0) {
    throw new Error('Incomplete sequence');
  }
  return result;
};

