class WordSearch {
  constructor(grid) {
    this.grid = grid;
  }

  find(words) {
    const directions = [
      [0, 1],   // right
      [0, -1],  // left
      [1, 0],   // down
      [-1, 0],  // up
      [1, 1],   // down-right
      [1, -1],  // down-left
      [-1, 1],  // up-right
      [-1, -1]  // up-left
    ];

    const result = {};
    const rows = this.grid.length;
    const cols = this.grid[0]?.length || 0;

    for (const word of words) {
      let found = false;

      for (let i = 0; i < rows && !found; i++) {
        for (let j = 0; j < cols && !found; j++) {
          for (const [dr, dc] of directions) {
            if (this._checkWord(word, i, j, dr, dc)) {
              const endRow = i + (word.length - 1) * dr;
              const endCol = j + (word.length - 1) * dc;

              result[word] = {
                start: [i + 1, j + 1],
                end: [endRow + 1, endCol + 1]
              };
              found = true;
              break;
            }
          }
        }
      }

      if (!found) {
        result[word] = undefined;
      }
    }

    return result;
  }

  _checkWord(word, startRow, startCol, dr, dc) {
    const rows = this.grid.length;
    const cols = this.grid[0].length;
    const endRow = startRow + (word.length - 1) * dr;
    const endCol = startCol + (word.length - 1) * dc;

    // Check bounds
    if (startRow < 0 || startRow >= rows || startCol < 0 || startCol >= cols) {
      return false;
    }
    if (endRow < 0 || endRow >= rows || endCol < 0 || endCol >= cols) {
      return false;
    }

    for (let i = 0; i < word.length; i++) {
      const r = startRow + i * dr;
      const c = startCol + i * dc;
      if (this.grid[r][c] !== word[i]) {
        return false;
      }
    }

    return true;
  }
}

