const SUPPORTED_OPERATIONS = {
  'plus': (a, b) => a + b,
  'minus': (a, b) => a - b,
  'multiplied by': (a, b) => a * b,
  'divided by': (a, b) => a / b
};

export const answer = (question) => {
  if (!question || !question.startsWith('What is ') || !question.endsWith('?')) {
    throw new Error('Invalid question format');
  }

  const expression = question.slice(8, -1).trim();
  if (!expression) {
    return 0;
  }

  // First, parse numbers and operations
  let i = 0;
  const numbers = [];
  const operators = [];

  while (i < expression.length) {
    // Skip spaces
    if (expression[i] === ' ') {
      i++;
      continue;
    }

    // Parse number (could be negative)
    let numStr = '';
    if (expression[i] === '-' && /\d/.test(expression[i + 1])) {
      numStr += expression[i];
      i++;
    }

    while (i < expression.length && /\d/.test(expression[i])) {
      numStr += expression[i];
      i++;
    }

    if (!numStr) {
      throw new Error('Syntax error: expected number');
    }

    numbers.push(parseInt(numStr, 10));

    // Try to parse operation
    if (i < expression.length) {
      let operationFound = false;

      // Check for "multiplied by" and "divided by" first (two words)
      for (const op of ['multiplied by', 'divided by']) {
        if (expression.substring(i, i + op.length + 1).trim() === op) {
          operators.push(op);
          i += op.length + 1;
          operationFound = true;
          break;
        }
      }

      if (!operationFound) {
        // Check single word operations
        for (const op of ['plus', 'minus']) {
          if (expression.substring(i, i + op.length + 1).trim() === op) {
            operators.push(op);
            i += op.length + 1;
            operationFound = true;
            break;
          }
        }
      }

      if (!operationFound && i < expression.length) {
        // Check if next chars are part of an invalid operation
        let nextWord = '';
        let tempI = i;
        while (tempI < expression.length && expression[tempI] !== ' ') {
          nextWord += expression[tempI];
          tempI++;
        }

        // Check if it's an unsupported operation
        const words = expression.substring(i).split(' ');
        let unsupported = false;
        for (let j = 0; j < words.length; j++) {
          const possibleOp = words.slice(0, j + 1).join(' ');
          if (SUPPORTED_OPERATIONS.hasOwnProperty(possibleOp)) {
            break;
          }
          if (words[j] === 'by' && j > 0) {
            const twoWordOp = words[j-1] + ' ' + words[j];
            if (SUPPORTED_OPERATIONS.hasOwnProperty(twoWordOp)) {
              break;
            }
          }
          // If we've checked enough words without finding a valid operation
          if (j >= 2) {
            unsupported = true;
            break;
          }
        }

        if (unsupported || words.length === 0) {
          throw new Error('Unsupported operation');
        }

        throw new Error('Syntax error: expected operation');
      }
    }
  }

  // Validate we have the right structure
  if (numbers.length - 1 !== operators.length) {
    throw new Error('Syntax error: invalid expression');
  }

  // Evaluate left to right
  let result = numbers[0];
  for (let j = 0; j < operators.length; j++) {
    const operation = SUPPORTED_OPERATIONS[operators[j]];
    result = operation(result, numbers[j + 1]);
  }

  return Math.floor(result);
};

