  while (remaining.length > 0) {
    remaining = remaining.trim();
    if (!remaining) break;

    // Check for multi-word operations first
    let foundOp = false;
    for (const op of ['multiplied by', 'divided by']) {
      if (remaining.startsWith(op + ' ') || remaining === op) {
        tokens.push({ type: 'op', value: op });
        remaining = remaining.substring(op.length).trim();
        foundOp = true;
        break;
      }
    }

    if (foundOp) continue;

    // Check for single-word operations
    for (const op of ['plus', 'minus']) {
      if (remaining.startsWith(op + ' ') || remaining === op) {
        tokens.push({ type: 'op', value: op });
        remaining = remaining.substring(op.length).trim();
        foundOp = true;
        break;
      }
