export class ZebraPuzzle {
  constructor() {
    this._solution = this.solve();
  }

  allPerms(arr) {
    const result = [];
    const permute = (a, m = []) => {
      if (a.length === 0) {
        result.push(m);
      } else {
        for (let i = 0; i < a.length; i++) {
          const curr = [...a];
          const next = curr.splice(i, 1);
          permute(curr, m.concat(next));
        }
      }
    };
    permute(arr);
    return result;
  }

  solve() {
    // Houses indexed 0-4
    // Colors: 0=red, 1=green, 2=ivory, 3=yellow, 4=blue
    // Nationalities: 0=Englishman, 1=Spaniard, 2=Ukrainian, 3=Norwegian, 4=Japanese
    // Pets: 0=dog, 1=snail, 2=fox, 3=horse, 4=zebra
    // Drinks: 0=coffee, 1=tea, 2=milk, 3=orangeJuice, 4=water
    // Hobbies: 0=dancing, 1=painting, 2=reading, 3=football, 4=chess

    const perms = this.allPerms([0, 1, 2, 3, 4]);

    // Constraint 10: Norwegian at house 0
    const natPerms = perms.filter(p => p[0] === 3);
    // Constraint 15: Blue at house 1 (next to Norwegian at 0)
    // Constraint 6: green = ivory + 1
    const colorPerms = perms.filter(p => {
      if (p[1] !== 4) return false;
      const greenIdx = p.indexOf(1);
      const ivoryIdx = p.indexOf(2);
      return greenIdx === ivoryIdx + 1;
    });
    // Constraint 9: House 2 (middle) drinks milk
    const drinkPerms = perms.filter(p => p[2] === 2);

    const names = ['Englishman', 'Spaniard', 'Ukrainian', 'Norwegian', 'Japanese'];

    for (const colors of colorPerms) {
      const redIdx = colors.indexOf(0);
      const greenIdx = colors.indexOf(1);
      const yellowIdx = colors.indexOf(3);

      for (const nats of natPerms) {
        // Constraint 2: Englishman in red house
        if (nats[redIdx] !== 0) continue;
        const spanIdx = nats.indexOf(1);
        const japIdx = nats.indexOf(4);

        for (const drinks of drinkPerms) {
          // Constraint 4: Green house drinks coffee
          if (drinks[greenIdx] !== 0) continue;
          // Constraint 5: Ukrainian drinks tea
          const ukrIdx = nats.indexOf(2);
          if (drinks[ukrIdx] !== 1) continue;

          for (const hobbies of perms) {
            // Constraint 8: Yellow house person is painter
            if (hobbies[yellowIdx] !== 1) continue;
            // Constraint 14: Japanese plays chess
            if (hobbies[japIdx] !== 4) continue;
            // Constraint 13: Football player drinks orange juice
            const footballIdx = hobbies.indexOf(3);
            if (drinks[footballIdx] !== 3) continue;
            // Constraint 7 pre-check: painterIdx needed later
            const painterIdx = hobbies.indexOf(1);

            for (const pets of perms) {
              // Constraint 3: Spaniard owns dog
              if (pets[spanIdx] !== 0) continue;
              // Constraint 7: Snail owner likes dancing
              const snailIdx = pets.indexOf(1);
              if (hobbies[snailIdx] !== 0) continue;
              // Constraint 11: Reader next to fox owner
