export class Zipper {
  constructor(focus, context = []) {
    this.focus = focus;
    this.context = context;
  }

  static fromTree(tree) {
    return new Zipper(tree);
  }

  toTree() {
    let current = this;
    while (current.context.length > 0) {
      current = current.up();
    }
    return current.focus;
  }

  value() {
    return this.focus.value;
  }

  left() {
    if (!this.focus.left) {
      return null;
    }
    const breadcrumb = {
      dir: 'left',
      value: this.focus.value,
      other: this.focus.right,
    };
    return new Zipper(this.focus.left, [breadcrumb, ...this.context]);
  }

  right() {
    if (!this.focus.right) {
      return null;
    }
    const breadcrumb = {
      dir: 'right',
      value: this.focus.value,
      other: this.focus.left,
    };
    return new Zipper(this.focus.right, [breadcrumb, ...this.context]);
  }

  up() {
    if (this.context.length === 0) {
      return null;
    }
    const [breadcrumb, ...rest] = this.context;
    let newFocus;
    if (breadcrumb.dir === 'left') {
      newFocus = {
        value: breadcrumb.value,
        left: this.focus,
        right: breadcrumb.other,
      };
    } else {
      newFocus = {
        value: breadcrumb.value,
        left: breadcrumb.other,
        right: this.focus,
      };
    }
    return new Zipper(newFocus, rest);
  }

  setValue(value) {
    return new Zipper(
      {
        value,
        left: this.focus.left,
        right: this.focus.right,
      },
      this.context,
    );
  }

  setLeft(tree) {
    return new Zipper(
      {
        value: this.focus.value,
        left: tree,
        right: this.focus.right,
      },
      this.context,
    );
  }

  setRight(tree) {
    return new Zipper(
      {
        value: this.focus.value,
        left: this.focus.left,
        right: tree,
      },
      this.context,
    );
  }
}
